balanced_idx      = np.concatenate([fraud_idx, non_fraud_sampled])

# create a balanced dataframe from the selected indices
fraud_balanced = fraud_dff.loc[balanced_idx].reset_index(drop=True)

print(f'\nAfter Undersampling:')
